choose.when:
select 
from biz_backpacker_chat_message
where order_id = #{orderId}
  and message_id > #{sinceId}
order by create_time asc, message_id asc
limit #{limit}

choose.otherwise:
select 
from (
    select 
    from biz_backpacker_chat_message
    where order_id = #{orderId}
    order by create_time desc, message_id desc
    limit #{limit}
) recent_messages
order by create_time asc, message_id asc

mapper.select:
select 
from biz_backpacker_chat_message
where order_id = #{orderId}
order by create_time asc, message_id asc
limit #{limit}
